var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"크윽, 윽…….","JPN":"く、うぐっ……","ENG":"Kgh... ngh...","TWN":"咳呃、呃……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"보기 좋던 위세가 결국 사경의 곡소리에 파묻혔구나.","JPN":"最初の威勢はどうした、うめき声になっているではないか。","ENG":"So that fine swagger ends drowned out by a death rattle.","TWN":"本來聲勢浩大，最後還是被絕境的哭聲埋沒了。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"지금이라도 무릎을 조아린다면, 내 친히 그간의 무도함을 용서해주마.","JPN":"今からでもひれ伏し許しを請えば、特別に先の無礼を許してやろう。","ENG":"Bow your knees even now, and I shall personally forgive your long insolence.","TWN":"要是現在下跪的話，我會饒恕他們此前的無道。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"지휘관급 개체는 움직이지 않고 교묘하게 하위 침식체들만 부리며 시간을 끌고 있다.","JPN":"指揮官級の個体は動かず、巧妙に下位侵食体を使って時間を稼いでいる。","ENG":"The Commander-class unit isn't moving, just slyly stalling with lower C.O.","TWN":"指揮官級個體沒有行動，只是巧妙地利用低級侵蝕體在拖延時間。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"가르강튀아의 동작 시간을 고려하면… 이 이상 시간이 끌리면 위험해.","JPN":"ガルガンティアの稼働時間を考えると……これ以上長引くのはまずい。","ENG":"If I factor in Garguantia's operating window... dragging this out any longer is dangerous.","TWN":"考量到加爾剛迪亞的活動時間…時間要是再拖下去就會有危險。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"솔직히 말하지, 제이나.","JPN":"正直に言おう、ジェイナ。","ENG":"I'll be frank, Jaina.","TWN":"老實說吧，婕娜。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"함선 엔진의 동력을 전달받는 상황은 아닌지라, 이 이상 가르강튀아를 운용하긴 힘드네.","JPN":"艦船エンジンの動力を供給してもらっている状況ではないため、これ以上ガルガンティアを運用するのは難しい。","ENG":"Without power fed from the ship's engine, I can't keep running Garguantia much longer.","TWN":"因為目前不是接收艦船引擎動力，很難再運用加爾剛迪亞了。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"적을 쓰러트리려면 다음 공격에 모든 걸 걸어야 해.","JPN":"敵を倒すためには、次の一撃にすべてをかけるしかない。","ENG":"If we're to fell the foe, we stake everything on the next strike.","TWN":"如果想擊敗敵人，就要在下次攻擊賭上一切。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……네, 이해했습니다.","JPN":"……はい、理解しました。","ENG":"...Understood.","TWN":"…是，我懂了。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님이 가실 수 있도록, 제가 시선을 끌게요!","JPN":"中将が行けるように、私が注意を引きます！","ENG":"I'll draw her attention so you can get through, Lieutenant General!","TWN":"我會吸引目光，讓中將可以過去！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"쯧. 아직 여력이 남아 있었나?","JPN":"ちっ、まだ力が残っていたか。","ENG":"Tsk. So you still had some strength left?","TWN":"嘖，難道你們還有餘力？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"허나, 자매들을 뚫고 내게 당도하는 건 불가능하다.","JPN":"だが、姉妹たちを突破して余にたどり着くなど不可能だ。","ENG":"But breaking through my sisters to reach me is impossible.","TWN":"但是要突破姐妹們，到我這裡來是不可能的。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"글쎄, 그건 어떠려나.","JPN":"さあ、それはどうかな。","ENG":"We'll see about that.","TWN":"這個嘛，這樣如何？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"……뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_SURPRISE"},"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"네놈, 어느 틈에 내 뒤로…!!","JPN":"貴様、いつの間に背後に……！！","ENG":"When did you slip behind me...?!","TWN":"妳這傢伙，什麼時候跑到我後面…！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"하아, 하아…….","JPN":"はあ、はあ……","ENG":"*Huff* *Huff...*","TWN":"哈啊、哈啊……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"해낸, 건가…?","JPN":"やった、のか……？","ENG":"Did we do it...?","TWN":"辦到了嗎…？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Fufu...","TWN":"呵呵……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"과연, 이제껏 카운터 능력을 선보이지 않은 이유가 이거였구나?","JPN":"なるほど。今までカウンター能力を見せなかった理由はこれだったのね。","ENG":"I see. So that is why you never showed Counter abilities until now?","TWN":"果然，原來這就是到目前為止都沒有展現制裁者能力的理由啊？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"목숨을 위협받는 와중에 적의 목을 노리다니… 제법이었어, 자기.","JPN":"命の危機に晒されている中で敵の首を狙うなんて……なかなかだったわ。","ENG":"Going for my throat while your life's on the line... not bad at all, darling.","TWN":"在生命受到威脅的情況下居然還覬覦敵人的脖子…真是厲害。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"지휘관급 개체가… 복수로 존재한다고?","JPN":"指揮官級の個体が……複数存在するだと？","ENG":"Commander-class units... exist in multiples?","TWN":"指揮官級個體…是為了復仇而存在？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"지휘관급이라는 말은 삼가줬으면 좋겠네. 우린 자매로서 그분에게 선별된 거거든.","JPN":"指揮官級という表現は控えてくれないかしら。私たちは姉妹としてあのお方に選ばれたの。","ENG":"I'd prefer you skip the Commander-class label. We are sisters, chosen by the queen.","TWN":"希望妳別再說指揮官級這種話了，我們做為姐妹，是被那位挑選出來的。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"가족의 공백을 가족으로 채우는 게, 별로 대수롭지는 않잖아?","JPN":"家族の空白を家族で埋める、別に珍しいことでもないでしょう？","ENG":"Filling a family's void with more family is hardly a big deal, is it?","TWN":"用家人來填補家人的空白，這沒什麼大不了吧？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님…!!","JPN":"中将……！！","ENG":"Lieutenant General...!!","TWN":"中將…！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"걱정 마. 자기는 머리가 좋으니까 다른 자매들도 좋아할 거야.","JPN":"心配しないで、貴方は賢いから姉妹たちも皆喜んでくれるわ。","ENG":"Do not fret. You are clever. My other sisters will like you too.","TWN":"別擔心，妳的腦袋很好，其他姐妹也會喜歡的。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"이제… 눈을 감고 편안함을 만끽하면 돼.","JPN":"もう……目を閉じて、安らぎに身を委ねなさい。","ENG":"Now... close your eyes and savor the comfort.","TWN":"現在…只要閉上眼睛享受安穩就行了。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"이런, 살고 싶지 않은 불나방이 더 있었나 보네.","JPN":"まあ、死にたがりの虫けらがまだ残っていたのね。","ENG":"Oh dear, seems there were more moths that do not value life.","TWN":"哎呀，看來還有不想活的飛蛾。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"다, 당신들은…….","JPN":"あ、あなたたちは……","ENG":"Y-you people are...","TWN":"你、你們是……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"아무래도 늦지 않은 모양이군.","JPN":"どうやら間に合ったようだな。","ENG":"Looks like we're not late after all.","TWN":"看來好像還來得及。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후후. 중요한 순간을 놓치지 않는 것이 바로 베테랑의 미덕이지.","JPN":"ふふ。肝心な瞬間に遅れないことこそ、ベテランの美徳。","ENG":"Haha. A veteran's virtue is never missing the crucial moment.","TWN":"呵呵，不錯過重要時刻就是老手的美德。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"모처럼 블랙네트워크에서 질 좋은 CSE 방호복을 구매한 보람이 있군.","JPN":"ブラックネットワークでハイクオリティーのCSE防護服を買った甲斐があったぜ。","ENG":"Good thing we splurged on quality CSE hazmat suits off the Dark Network.","TWN":"不枉費我在黑色網路買到品質不錯的CSE防護服。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};